        "front": "Definition of Gang Culture",
        "back": "A complex social phenomenon involving groups that share common interests, often associated with criminal activities."
      },
      {
        "front": "Core Characteristics of Gang Culture",
        "back": "Key traits include loyalty, identity, territory, and often a connection to criminal activities."
      },
      {
        "front": "Loyalty in Gang Culture",
        "back": "A fundamental aspect where members show unwavering allegiance to their gang and its members."
      },
      {
        "front": "Identity in Gang Culture",
        "back": "The sense of belonging and distinctiveness that members derive from their gang affiliation."
      }
    ]
  }
